package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;
  private Excluder excluderMock;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
    excluderMock = mock(Excluder.class);
  }

  @Test
  void excludeFieldsWithoutExposeAnnotation_shouldUpdateExcluderAndReturnThis() throws Exception {
    // Arrange
    // Set private field 'excluder' to mocked excluder
    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    excluderField.set(gsonBuilder, excluderMock);

    // Prepare mock behavior: when excludeFieldsWithoutExposeAnnotation() called, return a new Excluder instance (mocked)
    Excluder newExcluderMock = mock(Excluder.class);
    when(excluderMock.excludeFieldsWithoutExposeAnnotation()).thenReturn(newExcluderMock);

    // Act
    GsonBuilder returned = gsonBuilder.excludeFieldsWithoutExposeAnnotation();

    // Assert
    // Verify that excluder.excludeFieldsWithoutExposeAnnotation() was called once
    verify(excluderMock, times(1)).excludeFieldsWithoutExposeAnnotation();

    // Verify that the excluder field was updated to newExcluderMock
    Excluder updatedExcluder = (Excluder) excluderField.get(gsonBuilder);
    assertSame(newExcluderMock, updatedExcluder);

    // Verify the method returns the same GsonBuilder instance
    assertSame(gsonBuilder, returned);
  }
}
